import os
from pathlib import Path

ROOT     = Path(__file__).resolve().parents[2]
TEMPLATE = ROOT / "mkdocs.template.yml"
OUTPUT   = ROOT / "mkdocs.yml"
DOCS_RU  = ROOT / "docs" / "ru"
CODE_DIR = DOCS_RU / "dev" / "code"

# Directories inside dev/code/ to skip from nav scan
SKIP_CODE_DIRS = {"_nav_fragment.yml"}


def nav_path(md_file: Path) -> str:
    """Absolute path → relative to docs/ru/ for mkdocs nav."""
    return str(md_file.relative_to(DOCS_RU)).replace(os.sep, "/")


def file_title(stem: str) -> str:
    return stem.replace("_", " ").replace("-", " ").title()


def dir_title(name: str) -> str:
    return f"{name}/"


def scan_code_dir(src_dir: Path, indent: int) -> list[str]:
    """Recursively scan docs/ru/dev/code/ and build nav lines."""
    nav: list[str] = []
    pad       = "  " * indent
    inner_pad = "  " * (indent + 1)

    index_md = src_dir / "index.md"
    if not index_md.exists():
        return nav

    nav.append(f"{pad}- {dir_title(src_dir.name)}:")
    nav.append(f"{inner_pad}- Обзор: {nav_path(index_md)}")

    try:
        children = sorted(src_dir.iterdir())
    except PermissionError:
        return nav

    subdirs = [c for c in children
               if c.is_dir() and not c.name.startswith("_")]
    files   = [c for c in children
               if c.is_file() and c.suffix == ".md"
               and c.name != "index.md"
               and not c.name.startswith("_")]

    for sub in subdirs:
        nav.extend(scan_code_dir(sub, indent + 1))

    for f in files:
        nav.append(f"{inner_pad}- {file_title(f.stem)}: {nav_path(f)}")

    return nav


def build_nav() -> str:
    """Build the complete nav YAML string."""

    # Scan dev/code/ for auto-generated code reference
    code_nav_lines: list[str] = []
    if CODE_DIR.exists():
        for d in sorted(CODE_DIR.iterdir()):
            if d.is_dir() and not d.name.startswith("_"):
                code_nav_lines.extend(scan_code_dir(d, indent=0))

